import React, { useState } from 'react';
import auth from '../services/auth';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const res = await auth.login(email, password);
    setLoading(false);
    if (res.ok) {
      window.location.href = '/';
    } else {
      setError(res.message || 'Login failed');
    }
  }

  return (
    <div className="login-container" style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'var(--gradient-bg)',
      backgroundSize: '400% 400%',
      animation: 'gradientShift 15s ease infinite',
      position: 'relative',
      overflow: 'hidden',
      padding: '20px'
    }}>
      {/* Animated background elements */}
      <div className="bg-blob" style={{
        position: 'absolute',
        width: '800px',
        height: '800px',
        background: 'radial-gradient(circle, rgba(99, 102, 241, 0.15) 0%, transparent 70%)',
        top: '-20%',
        right: '-10%',
        filter: 'blur(80px)',
        animation: 'float 20s ease-in-out infinite'
      }}></div>
      <div className="bg-blob" style={{
        position: 'absolute',
        width: '600px',
        height: '600px',
        background: 'radial-gradient(circle, rgba(139, 92, 246, 0.1) 0%, transparent 70%)',
        bottom: '-10%',
        left: '-10%',
        filter: 'blur(60px)',
        animation: 'float 25s ease-in-out infinite reverse'
      }}></div>

      <div className="login-card scale-up" style={{
        width: '100%',
        maxWidth: '480px',
        background: 'rgba(13, 17, 35, 0.7)',
        backdropFilter: 'blur(30px)',
        WebkitBackdropFilter: 'blur(30px)',
        padding: '3.5rem',
        borderRadius: '32px',
        boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5), inset 0 0 0 1px rgba(255, 255, 255, 0.1)',
        border: '1px solid rgba(255, 255, 255, 0.1)',
        position: 'relative',
        zIndex: 1
      }}>
        <div style={{ textAlign: 'center', marginBottom: '3rem' }}>
          <div style={{
            width: '90px',
            height: '90px',
            margin: '0 auto 1.5rem',
            background: 'var(--gradient-primary)',
            borderRadius: '24px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '48px',
            boxShadow: '0 15px 30px rgba(99, 102, 241, 0.4)',
            animation: 'pulse 4s ease-in-out infinite'
          }}>
            🔐
          </div>
          <h3 style={{
            fontSize: '2.25rem',
            fontWeight: '900',
            color: 'white',
            margin: 0,
            marginBottom: '0.75rem',
            letterSpacing: '-0.03em',
            background: 'linear-gradient(to bottom, #fff, #94a3b8)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent'
          }}>
            Admin Portal
          </h3>
          <p style={{ margin: 0, color: 'var(--text-secondary)', fontSize: '1.0625rem', fontWeight: '500' }}>
            Enter your credentials to access the system.
          </p>
        </div>

        <form onSubmit={submit} style={{ display: 'grid', gap: '2rem' }}>
          <div className="input-group" style={{ margin: 0 }}>
            <label style={{
              display: 'flex',
              alignItems: 'center',
              gap: '0.75rem',
              fontSize: '0.875rem',
              fontWeight: '700',
              color: 'var(--text-primary)',
              marginBottom: '0.75rem',
              textTransform: 'uppercase',
              letterSpacing: '0.05em'
            }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z" />
                <polyline points="22,6 12,13 2,6" />
              </svg>
              Email Address
            </label>
            <input
              className="input"
              type="email"
              placeholder="admin@harari.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
              required
              style={{
                width: '100%',
                padding: '1rem 1.25rem',
                borderRadius: '16px',
                border: '1px solid rgba(255, 255, 255, 0.1)',
                background: 'rgba(0, 0, 0, 0.3)',
                color: 'white',
                fontSize: '1rem',
                transition: 'all 0.3s ease',
                outline: 'none'
              }}
            />
          </div>

          <div className="input-group" style={{ margin: 0 }}>
            <label style={{
              display: 'flex',
              alignItems: 'center',
              gap: '0.75rem',
              fontSize: '0.875rem',
              fontWeight: '700',
              color: 'var(--text-primary)',
              marginBottom: '0.75rem',
              textTransform: 'uppercase',
              letterSpacing: '0.05em'
            }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                <path d="M7 11V7a5 5 0 0 1 10 0v4" />
              </svg>
              Password
            </label>
            <div style={{ position: 'relative' }}>
              <input
                className="input"
                type={showPassword ? "text" : "password"}
                placeholder="••••••••"
                value={password}
                onChange={e => setPassword(e.target.value)}
                required
                style={{
                  width: '100%',
                  padding: '1rem 3.5rem 1rem 1.25rem',
                  borderRadius: '16px',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                  background: 'rgba(0, 0, 0, 0.3)',
                  color: 'white',
                  fontSize: '1rem',
                  transition: 'all 0.3s ease',
                  outline: 'none'
                }}
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                style={{
                  position: 'absolute',
                  right: '1rem',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-secondary)',
                  cursor: 'pointer',
                  padding: '0.5rem',
                  display: 'flex',
                  alignItems: 'center',
                  transition: 'color 0.2s'
                }}
              >
                {showPassword ? (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24" />
                    <line x1="1" y1="1" x2="23" y2="23" />
                  </svg>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" />
                    <circle cx="12" cy="12" r="3" />
                  </svg>
                )}
              </button>
            </div>
          </div>

          <button
            className="btn-primary hover-glow"
            disabled={loading}
            type="submit"
            style={{
              width: '100%',
              padding: '1.125rem',
              background: loading ? 'rgba(99, 102, 241, 0.5)' : 'var(--gradient-primary)',
              color: 'white',
              border: 'none',
              borderRadius: '16px',
              fontWeight: '800',
              fontSize: '1.125rem',
              cursor: loading ? 'not-allowed' : 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '0.75rem',
              transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
              boxShadow: loading ? 'none' : '0 10px 25px rgba(99, 102, 241, 0.4)',
              marginTop: '0.5rem'
            }}
          >
            {loading ? (
              <>
                <div className="loading-spinner" style={{ width: '22px', height: '22px', borderWidth: '3px', borderTopColor: 'white' }}></div>
                Authenticating...
              </>
            ) : (
              <>
                <span>Sign In to Dashboard</span>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <polyline points="9 18 15 12 9 6" />
                </svg>
              </>
            )}
          </button>
        </form>

        {error && (
          <div className="fade-in" style={{
            marginTop: '2rem',
            padding: '1.25rem',
            background: 'rgba(244, 63, 94, 0.1)',
            border: '1px solid rgba(244, 63, 94, 0.2)',
            color: 'var(--danger)',
            borderRadius: '16px',
            fontSize: '0.9375rem',
            fontWeight: '600',
            textAlign: 'center',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '0.75rem'
          }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <circle cx="12" cy="12" r="10" />
              <line x1="12" y1="8" x2="12" y2="12" />
              <line x1="12" y1="16" x2="12.01" y2="16" />
            </svg>
            {error}
          </div>
        )}

        <div style={{
          marginTop: '3rem',
          textAlign: 'center',
          paddingTop: '2rem',
          borderTop: '1px solid rgba(255, 255, 255, 0.05)'
        }}>
          <p style={{ margin: 0, color: 'var(--text-muted)', fontSize: '0.8125rem', fontWeight: '600', letterSpacing: '0.02em' }}>
            © 2025 HARARI SAVING & CREDIT SYSTEM • V2.0
          </p>
        </div>
      </div>

      <style>{`
        .input:focus {
          border-color: var(--primary) !important;
          background: rgba(0, 0, 0, 0.5) !important;
          box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.15) !important;
          transform: translateY(-1px);
        }
        .hover-glow:hover:not(:disabled) {
          transform: translateY(-2px);
          box-shadow: 0 15px 35px rgba(99, 102, 241, 0.5) !important;
          filter: brightness(1.1);
        }
        .hover-glow:active:not(:disabled) {
          transform: translateY(0);
        }
        @keyframes pulse {
          0%, 100% { transform: scale(1); box-shadow: 0 15px 30px rgba(99, 102, 241, 0.4); }
          50% { transform: scale(1.05); box-shadow: 0 20px 40px rgba(99, 102, 241, 0.6); }
        }
      `}</style>
    </div>
  );
}

export default Login;
